## Task Description

Integrate the CircuitState into the existing WorkerHealth struct and modify the health check loop to respect circuit states. This is the core implementation of the circuit breaker pattern.

## Current State

In `rchd/src/health.rs`:
```rust
pub struct WorkerHealth {
    consecutive_failures: u32,
    last_result: Option<HealthCheckResult>,
    current_status: WorkerStatus,
}
```

The health monitor runs checks at a fixed interval for all workers.

## Changes Required

### 1. Extend WorkerHealth
```rust
pub struct WorkerHealth {
    consecutive_failures: u32,
    last_result: Option<HealthCheckResult>,
    current_status: WorkerStatus,
    circuit: CircuitState,  // NEW
    circuit_config: CircuitBreakerConfig,  // NEW (or reference shared config)
}

impl WorkerHealth {
    /// Update health state and circuit based on check result
    pub fn update(&mut self, result: HealthCheckResult) {
        if result.healthy {
            self.handle_success(result);
        } else {
            self.handle_failure(result);
        }
    }

    fn handle_success(&mut self, result: HealthCheckResult) {
        self.consecutive_failures = 0;
        self.last_result = Some(result);

        match &self.circuit {
            CircuitState::HalfOpen { .. } => {
                // Probe succeeded - close the circuit
                tracing::info!("Circuit closing after successful probe");
                self.circuit = CircuitState::Closed;
                self.current_status = WorkerStatus::Healthy;
            }
            CircuitState::Closed => {
                // Normal success - check for degraded
                if result.response_time_ms > self.circuit_config.degraded_threshold_ms {
                    self.current_status = WorkerStatus::Degraded;
                } else {
                    self.current_status = WorkerStatus::Healthy;
                }
            }
            CircuitState::Open { .. } => {
                // Shouldn't happen - we only check when should_probe() is true
                unreachable!("Success while circuit is open");
            }
        }
    }

    fn handle_failure(&mut self, result: HealthCheckResult) {
        self.consecutive_failures += 1;
        self.last_result = Some(result);

        match &mut self.circuit {
            CircuitState::Closed => {
                if self.consecutive_failures >= self.circuit_config.failure_threshold {
                    self.trip_circuit();
                } else {
                    self.current_status = WorkerStatus::Degraded;
                }
            }
            CircuitState::HalfOpen { .. } => {
                // Probe failed - re-trip with increased backoff
                self.trip_circuit();
            }
            CircuitState::Open { .. } => {
                // Shouldn't happen
                unreachable!("Failure while circuit is open");
            }
        }
    }

    fn trip_circuit(&mut self) {
        let trip_count = match &self.circuit {
            CircuitState::Open { trip_count, .. } => trip_count + 1,
            _ => 1,
        };

        let cooldown = self.circuit_config.cooldown_for_trip(trip_count);
        let next_probe = Instant::now() + cooldown;

        tracing::warn!(
            trip_count = trip_count,
            cooldown_secs = cooldown.as_secs(),
            "Circuit tripped"
        );

        self.circuit = CircuitState::Open {
            tripped_at: Instant::now(),
            trip_count,
            next_probe_at: next_probe,
        };
        self.current_status = WorkerStatus::Unreachable;
    }

    /// Get current circuit state
    pub fn circuit_state(&self) -> &CircuitState {
        &self.circuit
    }
}
```

### 2. Modify Health Check Loop
```rust
// In HealthMonitor::start()

loop {
    ticker.tick().await;

    let workers = pool.all_workers().await;

    for worker in workers {
        let worker_id = worker.config.id.clone();
        let mut states = health_states.write().await;
        let health = states.entry(worker_id.clone()).or_default();

        // NEW: Check circuit state before performing health check
        match &health.circuit {
            CircuitState::Closed => {
                // Normal health check
                let result = check_worker_health(&worker, &config).await;
                health.update(result);
            }
            CircuitState::Open { next_probe_at, .. } => {
                if Instant::now() >= *next_probe_at {
                    // Time to probe - transition to half-open
                    tracing::info!(worker = %worker_id, "Circuit entering half-open state");
                    health.circuit = CircuitState::HalfOpen {
                        entered_at: Instant::now(),
                    };
                    // Perform probe
                    let result = check_worker_health(&worker, &config).await;
                    health.update(result);
                } else {
                    // Skip check - circuit still open
                    tracing::debug!(
                        worker = %worker_id,
                        "Skipping health check - circuit open"
                    );
                }
            }
            CircuitState::HalfOpen { .. } => {
                // Perform probe check
                let result = check_worker_health(&worker, &config).await;
                health.update(result);
            }
        }

        // Update worker pool status
        pool.set_status(&worker.config.id, health.current_status).await;
    }
}
```

