## Task Description

Implement the `rch status` CLI command that queries the daemon's /status endpoint and displays the information in a well-formatted, colorized output.

## Design

### CLI Interface
```bash
rch status                    # Default summary view
rch status --workers          # Detailed worker table
rch status --jobs             # Focus on recent builds
rch status --json             # Raw JSON output
rch status --watch            # Future: auto-refresh
```

### Output Formatting
```rust
// In rch/src/commands/status.rs (new file)

use colored::Colorize;
use comfy_table::{Table, presets::UTF8_FULL};

pub async fn run_status(args: StatusArgs) -> Result<()> {
    // Query daemon
    let status = match query_daemon_status(&args.socket).await {
        Ok(s) => s,
        Err(e) if is_connection_error(&e) => {
            print_daemon_not_running();
            return Ok(());
        }
        Err(e) => return Err(e),
    };

    if args.json {
        println!("{}", serde_json::to_string_pretty(&status)?);
        return Ok(());
    }

    print_header();
    print_daemon_info(&status.daemon);
    print_separator();

    if args.workers || (!args.jobs) {
        print_workers_table(&status.workers, &status.stats);
    }

    if args.jobs || (!args.workers) {
        print_separator();
        print_builds_table(&status.recent_builds);
    }

    if !status.issues.is_empty() {
        print_separator();
        print_issues(&status.issues);
    }

    Ok(())
}

fn print_header() {
    println!();
    println!("{}", "RCH Status".bold());
    println!("{}", "═".repeat(60));
    println!();
}

fn print_daemon_info(daemon: &DaemonInfo) {
    let uptime = format_duration(daemon.uptime_secs);
    let status_icon = "✓".green();

    println!("Daemon: {} Running (pid {}, uptime {})",
        status_icon,
        daemon.pid,
        uptime
    );
    println!("Socket: {}", daemon.socket_path);
    if let Some(ref config) = daemon.config_path {
        println!("Config: {}", config);
    }
}

fn print_workers_table(workers: &[WorkerInfo], stats: &StatusStats) {
    println!();
    println!("{} ({} healthy, {} degraded, {} unreachable):",
        "Workers".bold(),
        stats.healthy_workers.to_string().green(),
        stats.degraded_workers.to_string().yellow(),
        stats.unreachable_workers.to_string().red()
    );

    let mut table = Table::new();
    table.load_preset(UTF8_FULL);
    table.set_header(vec!["Worker", "Status", "Slots", "Speed", "Last Check"]);

    for worker in workers {
        let status_str = format_worker_status(&worker.status);
        let slots = format!("{}/{}", worker.used_slots, worker.total_slots);
        let speed = format!("{:.1}", worker.speed_score);
        let last_check = format_last_check(worker.last_health_check, worker.last_check_latency_ms);

        table.add_row(vec![
            &worker.id,
            &status_str,
            &slots,
            &speed,
            &last_check,
        ]);
    }

    println!("{}", table);
}

fn format_worker_status(status: &WorkerStatus) -> String {
    match status {
        WorkerStatus::Healthy => format!("{} Healthy", "✓".green()),
        WorkerStatus::Degraded => format!("{} Degraded", "⚠".yellow()),
        WorkerStatus::Unreachable => format!("{} Unreachable", "✗".red()),
        WorkerStatus::Draining => format!("{} Draining", "⏸".blue()),
        WorkerStatus::Disabled => format!("{} Disabled", "○".dimmed()),
    }
}

fn print_builds_table(builds: &[BuildRecord]) {
    println!();
    println!("{}:", "Recent Builds".bold());

    if builds.is_empty() {
        println!("  No recent builds");
        return;
    }

    let mut table = Table::new();
    table.load_preset(UTF8_FULL);
    table.set_header(vec!["Time", "Project", "Worker", "Result", "Duration"]);

    for build in builds.iter().take(10) {
        let time = format_relative_time(build.submitted_at);
        let worker = build.worker_id.as_deref().unwrap_or("-");
        let result = format_build_outcome(&build.outcome);
        let duration = build.duration_ms
            .map(|ms| format!("{:.1}s", ms as f64 / 1000.0))
            .unwrap_or_else(|| "running...".to_string());

        table.add_row(vec![
            &time,
            &build.project_id,
            worker,
            &result,
            &duration,
        ]);
    }

    println!("{}", table);
}

fn format_build_outcome(outcome: &BuildOutcome) -> String {
    match outcome {
        BuildOutcome::InProgress => "⋯".blue().to_string(),
        BuildOutcome::Success => "✓".green().to_string(),
        BuildOutcome::Failed { exit_code } => format!("{} {}", "✗".red(), exit_code),
        BuildOutcome::Cancelled => "⊘".yellow().to_string(),
        BuildOutcome::LocalFallback { .. } => format!("{} local", "↩".cyan()),
    }
}

fn print_issues(issues: &[Issue]) {
    println!();
    println!("{}:", "Issues".bold());

    for issue in issues {
        let icon = match issue.level {
            IssueLevel::Error => "✗".red(),
            IssueLevel::Warning => "⚠".yellow(),
            IssueLevel::Info => "ℹ".blue(),
        };

        println!("  {} {}", icon, issue.message);
        if let Some(ref suggestion) = issue.suggestion {
            println!("    {}", suggestion.dimmed());
        }
    }
}

fn print_daemon_not_running() {
    println!();
    println!("{} Daemon not running", "✗".red());
    println!();
    println!("Start the daemon with:");
    println!("  {}", "rch daemon start".cyan());
}

fn format_relative_time(time: DateTime<Utc>) -> String {
    let now = Utc::now();
    let diff = now - time;

    if diff.num_seconds() < 60 {
        format!("{}s ago", diff.num_seconds())
    } else if diff.num_minutes() < 60 {
        format!("{}m ago", diff.num_minutes())
    } else if diff.num_hours() < 24 {
        format!("{}h ago", diff.num_hours())
    } else {
        format!("{}d ago", diff.num_days())
    }
}

fn format_duration(secs: u64) -> String {
    if secs < 60 {
        format!("{}s", secs)
    } else if secs < 3600 {
        format!("{}m", secs / 60)
    } else if secs < 86400 {
        format!("{}h {}m", secs / 3600, (secs % 3600) / 60)
    } else {
        format!("{}d {}h", secs / 86400, (secs % 86400) / 3600)
    }
}
```

